/**
 * Indonesia CTR threshold gate (Law No. 8/2010 Art. 23).
 *
 * Transactions in IDR at or above IDR 500,000,000 (~$31k) in a
 * single business day require Cash Transaction Report filing to
 * PPATK within 14 working days. Modeled as BLOCK since the
 * platform has no REVIEW status — the compliance team reviews
 * the blocked transaction and files the CTR.
 *
 * Only fires on IDR-denominated transactions.
 */
export const handler = async (input) => {
  const tx = input.transaction;
  if (!tx) return { ledger_accounts: {} };

  const CTR_THRESHOLD = 500000000;

  if (tx.currency !== 'IDR') return { ledger_accounts: {} };
  if (typeof tx.amount !== 'number' || tx.amount < CTR_THRESHOLD) {
    return { ledger_accounts: {} };
  }

  const debtor = input.debtor_payment_account;
  if (!debtor) return { ledger_accounts: {} };

  const las = debtor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'id_ctr_threshold',
      block_reason: 'id_ctr_threshold',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
